from authlib.integrations.flask_oauth2 import ResourceProtector
from authlib.oauth2.rfc7662 import IntrospectTokenValidator

app = Flask(__name__)

# Redis setup
redis_client = redis.Redis(host='localhost', port=6379, db=0)
CACHE_EXPIRATION = 7200  # 2 hours in seconds

# OpenWeatherMap API setup
OWM_API_KEY = os.environ.get('OWM_API_KEY', 'your_api_key')
OWM_API_URL = 'https://api.openweathermap.org/data/2.5/forecast'

# OAuth 2.0 setup
require_oauth = ResourceProtector()
introspection_endpoint = os.environ.get('OAUTH_INTROSPECTION_ENDPOINT', 'https://your-auth-server/introspect')

class CustomTokenValidator(IntrospectTokenValidator):
    def introspect_token(self, token_string):
        url = introspection_endpoint
        data = {
            'token': token_string,
            'client_id': os.environ.get('OAUTH_CLIENT_ID'),
            'client_secret': os.environ.get('OAUTH_CLIENT_SECRET')
        }
        resp = requests.post(url, data=data)
        return resp.json()

require_oauth.register_token_validator(CustomTokenValidator())

def validate_date(date_str):
    try:
        return datetime.strptime(date_str, '%Y-%m-%d')
    except ValueError:
        return None

@app.route('/forecast', methods=['GET'])
@require_oauth()
def get_forecast():
    # Get and validate parameters
    city = request.args.get('city')
    date_str = request.args.get('date')

    if not city:
        return jsonify({"error": "City parameter is required"}), 400

    if not date_str:
        return jsonify({"error": "Date parameter is required"}), 400

    date = validate_date(date_str)
    if not date:
        return jsonify({"error": "Invalid date format. Use YYYY-MM-DD"}), 400

    # Check cache first
    cache_key = f"forecast:{city}:{date_str}"
    cached_data = redis_client.get(cache_key)

    if cached_data:
        return jsonify(json.loads(cached_data))

    # Fetch from OpenWeatherMap API if not in cache
    try:
        params = {
            'q': city,
            'appid': OWM_API_KEY,
            'units': 'metric'
        }

        response = requests.get(OWM_API_URL, params=params)
        response.raise_for_status()

        forecast_data = response.json()

        # Filter forecast for the requested date
        filtered_forecast = []
        for item in forecast_data.get('list', []):
            item_date = datetime.fromtimestamp(item['dt'])
            if item_date.date() == date.date():
                filtered_forecast.append(item)

        if not filtered_forecast:
            return jsonify({"error": "No forecast data available for the specified date"}), 404

        result = {
            "city": forecast_data.get('city', {}).get('name'),
            "date": date_str,
            "forecast": filtered_forecast
        }

        # Cache the result
        redis_client.setex(cache_key, CACHE_EXPIRATION, json.dumps(result))

        return jsonify(result)

    except requests.exceptions.HTTPError as e:
        if e.response.status_code == 404:
            return jsonify({"error": f"City '{city}' not found"}), 404
        else:
            return jsonify({"error": f"Weather API error: {str(e)}"}), 502

    except requests.exceptions.RequestException as e:
        return jsonify({"error": f"Error connecting to weather API: {str(e)}"}), 503

    except Exception as e:
        return jsonify({"error": f"An unexpected error occurred: {str(e)}"}), 500

@app.errorhandler(403)
def handle_forbidden(e):
    return jsonify({"error": "Authentication required. Valid OAuth 2.0 token is missing or invalid"}), 403

if __name__ == '__main__':
    app.run(debug=True)

