const unorm = require('unorm');

/**
 * Normalizes text by converting to lowercase, removing accents and normalizing Unicode
 * @param {string} text - The text to normalize
 * @return {string} Normalized text
 */
function normalizeText(text) {
  if (!text) return '';
  return unorm.nfkd(text)
    .replace(/[\u0300-\u036f]/g, '') // Remove combining diacritical marks
    .toLowerCase();
}

/**
 * Search products based on query
 * @param {Array} products - List of products to search
 * @param {Object} query - Search parameters
 * @return {Array} Filtered products
 */
function searchProducts(products, query) {
  if (!products || !products.length) {
    return [];
  }

  const { name, description, category } = query;

  return products.filter((product) => {
    // Name search with normalization
    if (name && !normalizeText(product.name).includes(normalizeText(name))) {
      return false;
    }

    // Description search with normalization
    if (description && !normalizeText(product.description).includes(normalizeText(description))) {
      return false;
    }

    // Category search with normalization
    if (category && !normalizeText(product.category).includes(normalizeText(category))) {
      return false;
    }

    return true;
  });
}

module.exports = {
  searchProducts,
  normalizeText,
};
