        $articleInPreferredLanguage = $this->getArticleInLanguage($article, $languageCode);

        return response()->json(['article' => $articleInPreferredLanguage]);
    }

    /**
     * Get the article in the specified language.
     *
     * @param  \App\Models\Article  $article
     * @param  string  $languageCode
     * @return \App\Models\Article
     */
    private function getArticleInLanguage(Article $article, $languageCode)
    {
        // If the article is already in the requested language
        if ($article->language_code === $languageCode) {
            return $article;
        }

        // Find the parent article if current article is a translation
        $parentId = $article->parent_article_id ?? $article->id;

        // Find the translation in requested language
        $translation = Article::where('parent_article_id', $parentId)
            ->where('language_code', $languageCode)
            ->first();

        // If translation exists, return it
        if ($translation) {
            return $translation;
        }

        // If no translation exists, get available languages
        $availableTranslations = Article::where(function($query) use ($parentId, $article) {
                $query->where('id', $parentId)
                      ->orWhere('parent_article_id', $parentId);
            })->get();

        // Add available languages to the article data
        $article->available_languages = $availableTranslations->pluck('language_code');

        return $article;
    }

    /**
     * Get all translations for an article.
     *
     * @param  int  $id
     * @return \Illuminate\Http\Response
     */
    public function getTranslations($id)
    {
        $article = Article::findOrFail($id);

        $parentId = $article->parent_article_id ?? $article->id;

        $translations = Article::where(function($query) use ($parentId) {
                $query->where('id', $parentId)
                      ->orWhere('parent_article_id', $parentId);
            })->with('language')->get();

        return response()->json(['translations' => $translations]);
    }
