class LanguagePreferenceMiddleware:
    def __init__(self, get_response):
        self.get_response = get_response

    def __call__(self, request):
        # Get language from Accept-Language header
        accept_language = request.META.get('HTTP_ACCEPT_LANGUAGE', '')

        if accept_language:
            # Parse the Accept-Language header and get the first preference
            languages = []
            for lang in accept_language.split(','):
                lang = lang.strip().split(';')[0]  # Remove quality values
                if lang:
                    languages.append(lang.lower())

            # Find the first supported language
            supported_languages = [lang[0] for lang in settings.LANGUAGES] if hasattr(settings, 'LANGUAGES') else ['en']

            for lang in languages:
                # Check exact match first
                if lang in supported_languages:
                    activate(lang)
                    break
                # Check language prefix (e.g., 'en' for 'en-US')
                lang_prefix = lang.split('-')[0]
                if lang_prefix in supported_languages:
                    activate(lang_prefix)
                    break
            else:
                # Fallback to default language
                activate(getattr(settings, 'LANGUAGE_CODE', 'en'))
        else:
            # Fallback to default language
            activate(getattr(settings, 'LANGUAGE_CODE', 'en'))

        response = self.get_response(request)
        return response

