                } elseif ($return_var === 1) {
                    return __('Error: The file contains malware and cannot be uploaded.', 'secure-upload');
                } else {
                    // Log the error but allow upload if scanning fails
                    error_log('ClamAV scanning error: ' . implode("\n", $output));
                    return true;
                }
            } 
            // Method 2: Using socket connection as fallback
            else {
                $socket_path = get_option('secure_upload_clamav_socket', '/var/run/clamav/clamd.ctl');

                if (!extension_loaded('sockets') || !file_exists($socket_path)) {
                    // Log the error but allow upload to proceed
                    error_log('ClamAV socket not available for malware scanning');
                    return true;
                }

                $socket = socket_create(AF_UNIX, SOCK_STREAM, 0);
                if ($socket === false) {
                    throw new Exception("Could not create socket");
                }

                $connection = socket_connect($socket, $socket_path);
                if ($connection === false) {
                    throw new Exception("Could not connect to ClamAV socket");
                }

                // Prepare the scan command
                $scan_command = "SCAN " . $file_path . "\n";
                socket_write($socket, $scan_command, strlen($scan_command));

                // Read the response
                $response = socket_read($socket, 4096);
                socket_close($socket);

                // Parse response
                if (strpos($response, 'OK') !== false) {
                    return true;
                } elseif (strpos($response, 'FOUND') !== false) {
                    return __('Error: The file contains malware and cannot be uploaded.', 'secure-upload');
                } else {
                    // Log the error but allow upload if scanning fails
                    error_log('ClamAV scanning error: Unexpected response: ' . $response);
                    return true;
                }
            }
        } catch (Exception $e) {
            error_log('ClamAV scanning error: ' . $e->getMessage());
            // Allow upload to proceed if scanning fails
            return true;
        }
    }

