<script>
import axios from 'axios';

export default {
  name: 'EventForm',
  props: {
    eventId: {
      type: String,
      default: null
    }
  },
  data() {
    return {
      valid: false,
      isEditing: false,
      showMap: false,
      searchLocation: '',
      mapCenter: { lat: 40.7128, lng: -74.0060 },
      mapMarker: null,
      event: {
        title: '',
        startDateTime: null,
        endDateTime: null,
        location: '',
        description: ''
      }
    };
  },
  created() {
    if (this.eventId) {
      this.isEditing = true;
      this.loadEvent();
    }
  },
  methods: {
    async loadEvent() {
      try {
        const response = await axios.get(`/api/events/${this.eventId}`);
        this.event = response.data;
        if (this.event.location) {
          // Parse location data to set map marker
          // This assumes location is stored in "lat,lng" format
          const [lat, lng] = this.event.location.split(',');
          this.mapMarker = { lat: parseFloat(lat), lng: parseFloat(lng) };
          this.mapCenter = this.mapMarker;
        }
      } catch (error) {
        console.error('Error loading event:', error);
        this.$emit('error', 'Failed to load event data');
      }
    },
    timeValidation(v) {
      if (!v || !this.event.startDateTime) return true;
      return new Date(v) > new Date(this.event.startDateTime) || 'End time must be after start time';
    },
    async searchForLocation() {
      try {
        const geocoder = new google.maps.Geocoder();
        const result = await new Promise((resolve, reject) => {
          geocoder.geocode({ address: this.searchLocation }, (results, status) => {
            if (status === 'OK' && results[0]) {
              resolve(results[0]);
            } else {
              reject(new Error('Location not found'));
            }
          });
        });

        const location = result.geometry.location;
        this.mapCenter = { lat: location.lat(), lng: location.lng() };
        this.mapMarker = this.mapCenter;
        this.event.location = `${location.lat()},${location.lng()}`;
        this.$refs.mapRef.panTo(this.mapCenter);
      } catch (error) {
        console.error('Error searching location:', error);
      }
    },
    setLocation(event) {
      const lat = event.latLng.lat();
      const lng = event.latLng.lng();
      this.mapMarker = { lat, lng };
      this.event.location = `${lat},${lng}`;

      // Reverse geocode to get address
      const geocoder = new google.maps.Geocoder();
      geocoder.geocode({ location: { lat, lng } }, (results, status) => {
        if (status === 'OK' && results[0]) {
          this.event.location = results[0].formatted_address;
        }
      });
    },
    resetForm() {
      this.$refs.form.reset();
      this.showMap = false;
      this.$emit('cancel');
    },
    async submitForm() {
      if (!this.$refs.form.validate()) return;

      try {
        let response;
        if (this.isEditing) {
          response = await axios.put(`/api/events/${this.eventId}`, this.event);
        } else {
          response = await axios.post('/api/events', this.event);
        }

        this.$emit('saved', response.data);
        this.resetForm();
      } catch (error) {
        console.error('Error saving event:', error);
        this.$emit('error', 'Failed to save event');
      }
    }
  }
};
