const crypto = require('crypto');
const axios = require('axios');
const { RateLimiter } = require('limiter');
const logger = require('../utils/logger');
const WebhookConfig = require('../models/WebhookConfig');

class WebhookService {
  constructor() {
    this.rateLimiters = new Map();
  }

  async create(userId, data) {
    try {
      const config = new WebhookConfig({
        userId,
        url: data.url,
        events: data.events,
        secretKey: data.secretKey,
        isActive: true
      });

      return await config.save();
    } catch (error) {
      logger.error('Failed to create webhook config', { userId, error: error.message });
      throw error;
    }
  }

  async getAll(userId) {
    try {
      return await WebhookConfig.find({ userId });
    } catch (error) {
      logger.error('Failed to fetch webhook configs', { userId, error: error.message });
      throw error;
    }
  }

  async getById(userId, webhookId) {
    try {
      return await WebhookConfig.findOne({ _id: webhookId, userId });
    } catch (error) {
      logger.error('Failed to fetch webhook config', { userId, webhookId, error: error.message });
      throw error;
    }
  }

  async update(userId, webhookId, data) {
    try {
      return await WebhookConfig.findOneAndUpdate(
        { _id: webhookId, userId },
        { $set: data },
        { new: true }
      );
    } catch (error) {
      logger.error('Failed to update webhook config', { userId, webhookId, error: error.message });
      throw error;
    }
  }

  async delete(userId, webhookId) {
    try {
      return await WebhookConfig.findOneAndDelete({ _id: webhookId, userId });
    } catch (error) {
      logger.error('Failed to delete webhook config', { userId, webhookId, error: error.message });
      throw error;
    }
  }

  async dispatchEvent(event, payload) {
    const webhooks = await WebhookConfig.find({ 
      events: event, 
      isActive: true 
    });

    logger.info(`Dispatching event ${event} to ${webhooks.length} webhooks`);

    webhooks.forEach(async (webhook) => {
      try {
        await this.sendWebhook(webhook, event, payload);
      } catch (error) {
        logger.error('Failed to dispatch webhook', { 
          webhookId: webhook._id,
          event,
          error: error.message 
        });
      }
    });
  }

  async sendWebhook(webhook, event, payload) {
    // Check rate limit
    if (!this.checkRateLimit(webhook._id)) {
      logger.warn('Rate limit exceeded for webhook', { webhookId: webhook._id });
      return;
    }

    const timestamp = Date.now();
    const signature = this.generateSignature(webhook.secretKey, payload, timestamp);

    try {
      await axios.post(webhook.url, payload, {
        headers: {
          'Content-Type': 'application/json',
          'X-Webhook-Signature': signature,
          'X-Webhook-Timestamp': timestamp,
          'X-Webhook-Event': event
        },
        timeout: 5000
      });

      logger.info('Webhook sent successfully', { 
        webhookId: webhook._id,
        event
      });
    } catch (error) {
      logger.error('Webhook request failed', { 
        webhookId: webhook._id,
        event,
        url: webhook.url,
        error: error.message
      });
      throw error;
    }
  }

  generateSignature(secretKey, payload, timestamp) {
    const stringToSign = JSON.stringify(payload) + timestamp;
    return crypto
      .createHmac('sha256', secretKey)
      .update(stringToSign)
      .digest('hex');
  }

  checkRateLimit(webhookId) {
    if (!this.rateLimiters.has(webhookId)) {
      // Allow 10 requests per minute
      this.rateLimiters.set(webhookId, new RateLimiter({ tokensPerInterval: 10, interval: 60000 }));
    }

    const limiter = this.rateLimiters.get(webhookId);
    return limiter.tryRemoveTokens(1);
  }

  verifySignature(payload, signature, timestamp, secretKey) {
    const expectedSignature = this.generateSignature(secretKey, payload, timestamp);
    return crypto.timingSafeEqual(
      Buffer.from(signature),
      Buffer.from(expectedSignature)
    );
  }
}

