from django.contrib import messages
from django.utils import timezone
from .models import Subscription
from .forms import SubscriptionForm
from django.utils.decorators import method_decorator
from django.views.decorators.csrf import csrf_protect

@method_decorator(csrf_protect, name='dispatch')
class SubscriptionView(View):
    template_name = 'subscription/manage_subscription.html'

    def get(self, request):
        user_id = request.user.id
        try:
            subscription = Subscription.objects.get(user_id=user_id)
            form = SubscriptionForm(instance=subscription)
        except Subscription.DoesNotExist:
            form = SubscriptionForm()

        return render(request, self.template_name, {'form': form})

    def post(self, request):
        user_id = request.user.id
        try:
            subscription = Subscription.objects.get(user_id=user_id)
            form = SubscriptionForm(request.POST, instance=subscription)
        except Subscription.DoesNotExist:
            form = SubscriptionForm(request.POST)

        if form.is_valid():
            subscription = form.save(commit=False)
            subscription.user_id = user_id
            subscription.update_timestamp = timezone.now()
            subscription.save()
            messages.success(request, 'Subscription updated successfully!')
        else:
            messages.error(request, 'Error updating your subscription. Please check your information.')

        return redirect('manage_subscription')
