import csv

def load_tasks(csv_file):
    tasks = []
    with open(csv_file, 'r') as file:
        reader = csv.DictReader(file)
        for row in reader:
            tasks.append({
                'name': row['name'],
                'priority': int(row['priority']),
                'duration': int(row['duration'])
            })
    return tasks

def schedule_tasks(tasks):
    return sorted(tasks, key=lambda x: (x['priority'], x['duration']))

def print_schedule(tasks):
    print("Schedule:")
    for i, task in enumerate(tasks, 1):
        print(f"{i}. {task['name']} (Priority: {task['priority']}, Duration: {task['duration']})")

def main(csv_file):
    tasks = load_tasks(csv_file)
    scheduled_tasks = schedule_tasks(tasks)
    print_schedule(scheduled_tasks)

if __name__ == "__main__":
    main("tasks.csv")
